import random
import numpy as np
from time import time
from rory.core.interfaces.cipherscheme_result import CipherschemeResult
from typing import Tuple,List
import numpy.typing as npt

"""
Description: 
	class to represent a symmetric encryption scheme
Attributes:
    _round: Flag to know if decryption needs to be rounded based on plaintext type
"""
class Liu(object):
	def __init__(self,**kwargs):
		self.round = kwargs.get("round",False)



	def generate_random_np(self,low:int, high:int, size:int,seed:int=42)->npt.NDArray:
		assert(low < high)
		np.random.seed(seed=seed)
		return np.random.uniform(low=low,high=high, size=size)
	""" 
	Description: Generate a uniform distributed numbers [0,1]
	"""
	def generateRandom(self):
		self.r = random.uniform(0,1)
		return self.r


	"""
    Description: Generates the secret key (SK) used to encrypt and decrypt
    Attributes: 
		m: mumber of attributes of SK
	Constraints:
        1. m >= 3
		2. the last tp: if (km + sm + tm)==0 it must be generated again.
		3. sk -> [(k_1,s_1,t_1)...(k_m,s_m,t_m)]
    """
	def secretKey(self, m:int) -> List[Tuple[float,float,float]]: 
		self.sk = []
		zero_tp = (0,0,0)
		for i in range(m):
			tp = self.generateRandom(),self.generateRandom(),self.generateRandom() # generate triplets
			if(i==(m-1)): 
				while(zero_tp == tp):
					tp = self.generateRandom(), self.generateRandom(), self.generateRandom()
			self.sk.append(tp)
		return self.sk


	"""
	Description: split a plaintext matrix into vectors
    """
	def encryptMatrix(self, plaintext_matrix:npt.NDArray, secret_key:List[Tuple[float,float,float]], m:int,seed:int = 42,np_random:bool=False) -> CipherschemeResult:
		start_time = time()
		results = []
		for v in plaintext_matrix:
			result = self.encryptVector(
				plaintext_vector  = v,
				secret_key = secret_key,
				m         = m,
				seed=seed, 
				np_random=np_random
			)
			results.append(result)
		end_time   = time()
		encryption_time = end_time-start_time
		return CipherschemeResult(
			matrix         =np.array( results), 
			time           = encryption_time,
			operation_type = "encrypt"
		)

	"""
	description: split a plaintext vector into scalars
    """
	def encryptVector(self, plaintext_vector:npt.NDArray, secret_key:List[Tuple[float,float,float]], m:int,seed:int = 42,np_random:bool=False) -> List[float]:
		results = []
		for v in plaintext_vector:
			result = self.encryptScalar(
				plaintext  = v,
				secret_key = secret_key,
				m          = m,
				seed       = seed,
				np_random  = np_random
			)
			results.append(result)
		return results

	"""
	description: Encrypt a plaintext using SK
    """
	def vectorizeEncryptMatrix(self,plaintext_matrix:npt.NDArray, secret_key:List[Tuple[float,float,float]], m:int) -> CipherschemeResult:
		f                = self.curryingEncryptScalar(secret_key,m)
		fx               = np.vectorize(f ,otypes =[object] )
		start_time       = time()
		M_               = np.asarray(list(map(lambda x: list(x),fx(plaintext_matrix.flatten()).tolist()))).flatten().reshape(plaintext_matrix.shape[0],plaintext_matrix.shape[1],m)
		end_time         = time()
		encryption_time  = end_time-start_time
		return CipherschemeResult(
			matrix         = M_, 
			time           = encryption_time,
			operation_type = "encrypt"
		)
		
	"""
	description: Encrypt a plaintext using SK
	attributes:
		v: plaintext
		sk: secret key
		m: number of attributes of SK
	constraints:
		1. E1: sk[0][0] * sk[0][2] * v + sk[0][1] * self.R[m-1] + sk[0][0] * (self.R[0] - self.R[m-2])
		2. Ei: sk[i][0] * sk[i][2] * v + sk[i][1] * self.R[m-1] + sk[i][0] * (self.R[i] - self.R[i-1])
		3. Em: sk[m-1][0] + sk[m-1][1] + sk[m-1][2]) * self.R[m-1]
		<ERROR> FIX IT LATER 
    """
	def curryingEncryptScalar(self,secret_key:List[Tuple[float,float,float]], m:int) -> List: 
		def __inner(v):
			self.round = True if(type(v) == int or type(v) == np.int64) else False
			self.E     = []
			self.R     = [ self.generateRandom() for i in range (m) ]
			e1         =  self.__eEncrypt(
				ki = secret_key[0][0],
				ti = secret_key[0][2],
				v  = v, 
				si = secret_key[0][1],
				rm = self.R[m-1],
				rrdiff = (self.R[0]-self.R[m-2])
			)
			self.E.append(e1) 
			for i in range(1,m-1): #Ei formula
				ei =  self.__eEncrypt(
					ki = secret_key[i][0],
					ti = secret_key[i][2],
					v  = v, 
					si = secret_key[i][1],
					rm = self.R[m-1],
					rrdiff = (self.R[i]-self.R[i-1])
				)
				self.E.append(ei)	
			self.E.append((secret_key[m-1][0] + secret_key[m-1][1] + secret_key[m-1][2]) * self.R[m-1]) #Em Formula
			return self.E
		return __inner


	"""
	description: Encrypt a plaintext using SK
	attributes:
		v: plaintext
		sk: secret key
		m: number of attributes of SK
	constraints:
		1. E1: sk[0][0] * sk[0][2] * v + sk[0][1] * self.R[m-1] + sk[0][0] * (self.R[0] - self.R[m-2])
		2. Ei: sk[i][0] * sk[i][2] * v + sk[i][1] * self.R[m-1] + sk[i][0] * (self.R[i] - self.R[i-1])
		3. Em: sk[m-1][0] + sk[m-1][1] + sk[m-1][2]) * self.R[m-1]
    """
	def encryptScalar(self, plaintext:float, secret_key:List[Tuple[float,float,float]], m:int,seed:int = 42,np_random:bool=False) -> List: 
		E     = []
		R     =  self.generate_random_np(low=0,high=1, size=m, seed=seed) if np_random  else [ self.generateRandom() for i in range (m) ]


		e1         =  self.__eEncrypt( #E1 formula
			ki = secret_key[0][0],
			ti = secret_key[0][2],
			v  = plaintext, 
			si = secret_key[0][1],
			rm = R[m-1],
			rrdiff = (R[0]-R[m-2])
		)
		E.append(e1) 
		for i in range(1,m-1): #Ei formula
			ei =  self.__eEncrypt(
				ki = secret_key[i][0],
				ti = secret_key[i][2],
				v  = plaintext, 
				si = secret_key[i][1],
				rm = R[m-1],
				rrdiff = (R[i]-R[i-1])
			)
			E.append(ei)	
		E.append((secret_key[m-1][0] + secret_key[m-1][1] + secret_key[m-1][2]) * R[m-1]) #Em Formula
		return E


	"""
    description: Generates the necessary tp for the encrypt method
    attributes:
        ki, ti, si:  real numbers
        v: plaintext
        rm: record at position m
		rrdiff: resta de r1 - rm-1
	"""
	def __eEncrypt(self, ki:float, ti:float, v:float, si:float, rm:float, rrdiff:float) -> float:
		return ki * ti * v + si * rm + ki * rrdiff


	"""
	description: split a ciphertext matrix into vectors
    """
	def decryptMatrix(self, ciphertext_matrix:npt.NDArray, secret_key:List[Tuple[float,float,float]], m:int) -> CipherschemeResult:
		start_time = time()
		results = []
		for c in ciphertext_matrix:
			result = self.decryptVector(
				ciphertext_vector = c,
				secret_key = secret_key,
				m          = m
			)
			results.append(result)
		end_time   = time()
		decryption_time = end_time-start_time
		return CipherschemeResult(
			matrix         = np.array(results), 
			time           = decryption_time,
			operation_type = "encrypt"
		)
		
		
	"""
	description: split a ciphertext vector into scalars
    """
	def decryptVector(self, ciphertext_vector:npt.NDArray, secret_key:List[Tuple[float,float,float]], m:int, **kwargs) -> List:
		results = []
		for c in ciphertext_vector:
			result = self.decryptScalar(
				ciphertext = c,
				secret_key = secret_key,
				m          = m
			)
			results.append(result)
		return results #[ self.decryptScalar(**new_kwargs(c)) for c in cs ]


	"""    
    description: Decrypt a ciphertext using SK
	attributes:
		E: ciphertext
		sk: secret key
		m: number of attributes of SK
	"""
	def curryingDecryptScalar(self,secret_key:List[Tuple[float,float,float]], m:int): 
		def __inner(E):
			t,e = 0,0
			for i in range(m-1):
				ti = secret_key[i][2]
				t += ti
			s = (E[m-1]) / (secret_key[m-1][0] + secret_key[m-1][1] + secret_key[m-1][2])
			for i in range(m-1):
				ei = (E[i] - s * secret_key[i][1])/ secret_key[i][0]
				e += ei
			v = float(e)/float(t)
			return int(np.around(v,decimals=2)) if(self.round) else v
		return __inner


	def vectorizeDecryptMatrix(self, ciphertext_matrix:npt.NDArray, secret_key:List[Tuple[float,float,float]], m:int) -> CipherschemeResult:
		f                = self.curryingDecryptScalar(secret_key,m)
		fx               = np.vectorize(f ,otypes =[object] )
		start_time       = time()
		M_               = fx(ciphertext_matrix.flatten())
		end_time         = time()
		decryption_time  = end_time-start_time
		return CipherschemeResult(
			matrix         = M_,
			time           = decryption_time,
			operation_type = "decrypt" )

	"""    
    description: Decrypt a ciphertext using SK
	attributes:
		E: ciphertext
		sk: secret key
		m: number of attributes of SK
	"""
	def decryptScalar(self, ciphertext:List, secret_key:List[Tuple[float,float,float]], m:int) -> float:  
		t,e = 0,0
		for i in range(m-1):
			ti = secret_key[i][2]
			t += ti
		s = (ciphertext[m-1]) / (secret_key[m-1][0] + secret_key[m-1][1] + secret_key[m-1][2])
		for i in range(m-1):
			ei = (ciphertext[i] - s * secret_key[i][1])/ secret_key[i][0]
			e += ei
		v = float(e)/float(t)
		return int(np.around(v,decimals=2)) if(self.round) else v


	"""
	description: Addition of two ciphertexts
	attributes:
		E1: first ciphertext
		E2: second ciphertext
    """
	@staticmethod
	def add(ciphertext_1:List[float], ciphertext_2:List[float]) -> List[float]:
		return (np.array(ciphertext_1) + np.array(ciphertext_2)).tolist()

	
	"""
	description: Multiplication of two ciphertexts
	attributes:
		E1: first ciphertext
		E2: second ciphertext
    """
	@staticmethod
	def multiply(ciphertext_1:List[float], ciphertext_2:List[float]) -> List[float]:
		ciphertext_3 = []
		m            = len(ciphertext_1)
		for i in range(m):
			for j in range(m):
				ciphertext_3.append(ciphertext_1[i] * ciphertext_2[j])
		return ciphertext_3


	"""
	description: Check multiplication of two ciphertexts
	attributes:
		E: ciphertext
		sk: secret key
		m: number of attributes of SK
    """
	@staticmethod
	def decrypt_multiply(self, ciphertext:List[float], secret_key:List[Tuple[float,float,float]], m:int) -> float:
		v1,v = [],[]
		for i in range(len(ciphertext)):
			v1.append(ciphertext[i])
			if ((i%m)==(m-1)):
				v.append(self.decryptScalar(ciphertext = v1, secret_key = secret_key, m = m))
				v1 = []
		self.E3 = self.decryptScalar(ciphertext = v, secret_key = secret_key, m = m)
		return self.E3

	""" 
	description: Multiply a ciphertext by a plaintext
	attributes:
		v1: plaintext
		E1: ciphertext
    """
	@staticmethod
	def multiply_c(scalar:float, ciphertext_1:List[float]) -> List[float]:
		E3 = []
		m  = len(ciphertext_1)
		for i in range(m):
			E3.append(scalar * ciphertext_1[i])
		return E3

	"""
	description: Subtract two ciphertexts
	attributes:
		E1: first ciphertext
		E2: second ciphertext
		m: number of attributes of SK
	"""
	@staticmethod
	def subtract(ciphertext_1:List[float], ciphertext_2:List[float]) -> List[float]:
		E3 = []
		m  = len(ciphertext_1)
		s1 = Liu.multiply_c(scalar = -1, ciphertext_1 = ciphertext_2)
		E3 = Liu.add(ciphertext_1 = ciphertext_1, ciphertext_2 = s1)
		return E3
	


